<script>
import Nav from '@/components/Nav.vue';


export default {
    name: "CameraLayout",
    data() {
        return {
            visible: false,  
        }

    },
    methods: {
        toggleCamera() {
        this.createCameraStream();
        },
        createCameraStream() {
            const constarints = (window.constarints = {
                audio: false,
                video: true
            });
            navigator.mediaDevices.getUserMedia(constarints)
                .then(stream => {
                    this.$refs.camera.srcObject = stream;
                }).catch(error => {
                    alert("Error: "+ error);
                })
        },
    },
    components: {
        Nav,
    }
    
}
</script>

<template>
<div class="main">
    <div class="burger" @click="visible = true" v-if="!visible">
        <svg viewBox="0 0 100 80" width="40" height="40">
        <rect width="100" height="20"></rect>
        <rect y="30" width="100" height="20"></rect>
        <rect y="60" width="100" height="20"></rect>
        </svg>
    </div>

    <div class="div_nav">
        <Nav v-if="visible" @exit="visible = false" />
    </div>

    <div class="camera">
        <div class="camera_div" >
            <div class="camera-shutter"></div>
            <video autoplay ref="camera" :width="350" :height="500"></video>
            <canvas ref="canvas" :width="350" :height="500"></canvas>
        </div>
        <div class="photo" @click="toggleCamera">
            <img src="../assets/photo.svg" alt="photo_svg" class="photo_icon">
        </div>
    </div>

    
</div>
</template>

<style scoped>
    .main {
        display: flex;
        flex-direction: column;
        
    }
    .camera {
        display: flex;
        flex-direction: column;
        width: 100vw;
        align-items: center;
        gap: 20px;
        
    }
    .camera_div {
        background: grey;
        width: 80vw;
        height: 50vh;
        border-radius: 30px;
    }
    .camera {
        position: absolute;
        
        top:10vh;
    }
    .photo {
        width:15vw;
    }
    .photo_icon {
        width: 100%;
    }
</style>