<script>
    export default {
        name: "StartLayout",
        data() {
            return {
                start:true,
                login_up:true,
            }
        },
        methods: {
            goToUserPage() {
               this.$router.push('/user') 
            },
            
        }
    };
    
</script>

<template >

    <div class="main">
        <div v-if="start" class="start">
            <img src="../assets/Logo.svg" alt="Logo">
            <div class="back_button">
                <button class="button_" @click="this.start = false">Начать</button>
                <div class="col1"></div>
                <div class="col2"></div>
                <div class="col3"></div>
            </div>
            
        </div>
        <div v-if="!start" class="reg">
            <div class="up">
                <button class="reg_up1"  :class="{'active': login_up}" @click="this.login_up = true">Login Up</button>
                <button class="reg_up2" :class="{'active': !login_up}" @click="this.login_up = false">Sign Up</button>
            </div>
            <div class="main_reg">
                <div v-if="login_up" class="login_up" >
                    <input type="email" class="input_reg" placeholder="Email"/>
                    <input type="password" class="input_reg" placeholder="Password" />
                    <button class="but_login" @click="goToUserPage">Войти</button>
                </div>
                <div v-if="!login_up" class="sign_up" >
                    <input class="input_reg" placeholder="Login"/>
                    <input type="email" class="input_reg" placeholder="Email"/>
                    <input type="password" class="input_reg" placeholder="Password"/>
                    <button class="but_sign" @click="goToUserPage">Зарегистрироваться</button>
                </div>
            </div>


        </div>
    </div>


</template>

<style scoped>

    *{
        box-sizing: border-box;
        padding: 0;
        margin: 0;
    }

    

    .main{
        display:flex;
        justify-content: center;
        margin: 10vh 0vh 0vh 0vh;

    }


    .start {
        display:flex;
        flex-direction: column;
        width: 100vw;
        

    }
    .back_button {
        display:flex;
        justify-content: center;

        border-radius: 15px;
        padding: 15px 0px;
        margin: 30px 10px;
        border: 2px solid black;

        
    }
    .button_ {
        border: none;
        background: none;
        height: 100%;
        width: 100%;
        font-size: 16px;
        font-weight: 900;
    }
    .reg {
        position: absolute;
        width: 90svw;
        display: flex;
        flex-direction: column;
    }
    .up {
        display: flex;
        width: 100%;
        padding: 5px 10px;
        justify-content: space-between;
    }
    .reg_up1, .reg_up2 {
        padding: 4px 10px;
        border: none;
        align-self: flex-start;
        border-radius: 10px;
        
    }

    .reg_up1, .reg_up2 {
        background-color: rgba(255,255,255,0.9);
        transition: background-color, 0.5s;
    }
     

    .active {
        background-color: rgba(255,255,255,0.0);
    }

    

    .main_reg {
        background-color: none;
        border-radius: 10px;
        margin-top: 20px;
        margin: 0px 5px;
        
        
        height: 50vh;
        
    }
    .login_up, .sign_up{
        display: flex;
        flex-direction: column;
        justify-content: space-evenly;
        height: 100%;
        border: 1px solid black;
        padding:0px 15px;
        border-radius: 20px ;
        background: rgba(213, 213, 213,0.1);

        transition: opacity 1s;
    }

    .input_reg {
        padding: 15px 5px;
        border: 1px solid black;
        border-radius: 10px;
        font-size: 20px;
        font-weight: 600;
        background-color: rgba(255,255,255,0.6);
    }

    .but_sign, .but_login {
        background: none;
        padding: 10px 0px;
        margin: 0px 20%;
        border-radius: 50px ;
    }

</style>