<script>

export default {
    name: "Col-nav",
    data(){
        return {
           list_vis:true
        }
    },
    methods: {
        shutdown: function() {
            this.$emit("exit");
            this.list_vis = false;
        },
        goToUserPage() {
               this.$router.push('/user') 
            },
        goToCameraPage() {
            this.$router.push('/user/camera') 
        },
        goToCollectionPage() {
               this.$router.push('/user/collection') 
            },
        goToAboutPage() {
            this.$router.push('/about') 
        },
    }
}
</script>


<template>
    <div class="burg_menu" v-if="list_vis">
        <div class="exit_menu">
            <img class="icon_escape" src="../assets/back_icon.svg" alt="back icon" @click="shutdown">
        </div>
        <nav class="navi">
            <ul class="list">
                <hr>
                <li class="element" @click="goToUserPage">Профиль</li>
                <hr>
                <li class="element" @click="goToCameraPage">Камера</li>
                <hr>
                <li class="element" @click="goToCollectionPage">Коллекция</li>
                <hr>
                <li class="element_about" @click="goToAboutPage">О нас</li>
            </ul>
        </nav>
    </div>
</template>

<style scoped>
    .burg_menu {
        background: rgba(213, 213, 213,0.8);
        border-radius:30px;
        margin: 5px 10px;
        border: 1px solid black;
        
    }
    .element {
        font-size: 20px;
        font-weight: 600;
    }
    .exit_menu {
        width: 100%;
        display: flex;
        justify-content: flex-end;
        padding: 15px 15px 15px 0px;

    }

    .icon_escape {
        width: 25px;
        height: 25px;;
    }

    li{
        list-style-type: none; 
    }

    .element {
        padding-left: 30px;
        margin: 10px 0px;
    }

    .list {
        display: flex;
        flex-direction: column;
    }

    .element_about {
        margin-top: 40px;
        align-self: flex-end;
        padding: 0px 15px 5px 0px;
    }
    
</style>